function hrd_Fellowship_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('hrd_Fellowship');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'year' => Request::val('year', '2020-21'),
		'name' => Request::val('name', ''),
		'gender' => Request::val('gender', 'Male'),
		'id_no' => Request::val('id_no', ''),
		'institute_name' => Request::val('institute_name', ''),
		'Department' => Request::val('Department', ''),
		'Qualification' => Request::val('Qualification', ''),
		'Fellowship_Type' => Request::val('Fellowship_Type', ''),
		'cast_category' => Request::val('cast_category', 'SC'),
		'Start_Date' => Request::dateComponents('Start_Date', ''),
		'End_Date' => Request::dateComponents('End_Date', ''),
		'status' => Request::val('status', ''),
		'founded_by' => Request::val('founded_by', ''),
		'Amount_Granted' => Request::val('Amount_Granted', ''),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('hrd_Fellowship', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		hrd_Fellowship_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function hrd_Fellowship_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function hrd_Fellowship_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('hrd_Fellowship', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: hrd_Fellowship_before_delete
	if(function_exists('hrd_Fellowship_before_delete')) {
		$args = [];
		if(!hrd_Fellowship_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `hrd_Fellowship` WHERE `id`='{$selected_id}'", $eo);

	// hook: hrd_Fellowship_after_delete
	if(function_exists('hrd_Fellowship_after_delete')) {
		$args = [];
		hrd_Fellowship_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='hrd_Fellowship' AND `pkValue`='{$selected_id}'", $eo);
}

function hrd_Fellowship_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('hrd_Fellowship', $selected_id, 'edit')) return false;

	$data = [
		'year' => Request::val('year', ''),
		'name' => Request::val('name', ''),
		'gender' => Request::val('gender', ''),
		'id_no' => Request::val('id_no', ''),
		'institute_name' => Request::val('institute_name', ''),
		'Department' => Request::val('Department', ''),
		'Qualification' => Request::val('Qualification', ''),
		'Fellowship_Type' => Request::val('Fellowship_Type', ''),
		'cast_category' => Request::val('cast_category', ''),
		'Start_Date' => Request::dateComponents('Start_Date', ''),
		'End_Date' => Request::dateComponents('End_Date', ''),
		'status' => Request::val('status', ''),
		'founded_by' => Request::val('founded_by', ''),
		'Amount_Granted' => Request::val('Amount_Granted', ''),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
	];

	if($data['year'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Year': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['gender'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Gender': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('hrd_Fellowship', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: hrd_Fellowship_before_update
	if(function_exists('hrd_Fellowship_before_update')) {
		$args = ['old_data' => $old_data];
		if(!hrd_Fellowship_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'hrd_Fellowship',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="hrd_Fellowship_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('hrd_Fellowship', $data['selectedID'], calculated_fields()['hrd_Fellowship']);

	// hook: hrd_Fellowship_after_update
	if(function_exists('hrd_Fellowship_after_update')) {
		if($row = getRecord('hrd_Fellowship', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!hrd_Fellowship_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('hrd_Fellowship', $selected_id);
}

